import WebSocket from 'ws';
import { createClient } from '@supabase/supabase-js';
import fs from 'fs';

// 1. Setup Configuration
const GEMINI_API_KEY = process.env.GEMINI_API_KEY;
const SUPABASE_URL = process.env.SUPABASE_URL;
const SUPABASE_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY;

// Use the current stable Live API model string
const MODEL = "models/gemini-2.0-flash-exp"; 
const URL = `wss://generativelanguage.googleapis.com/ws/google.ai.generativelanguage.v1beta.GenerativeService.BidiGenerateContent?key=${GEMINI_API_KEY}`;

const supabase = createClient(SUPABASE_URL, SUPABASE_KEY);

async function runTest() {
    console.log("🚀 Initializing Targeted Injection Test...");

    const ws = new WebSocket(URL);

    // --- HELPER: Fetch from Supabase Storage ---
    async function getSupabaseFile(path) {
        console.log(`fetching: ${path}...`);
        const { data, error } = await supabase.storage.from('your-bucket-name').download(path);
        if (error) throw error;
        const arrayBuffer = await data.arrayBuffer();
        return Buffer.from(arrayBuffer).toString('base64');
    }

    ws.on('open', function open() {
        console.log("✅ Connected to Gemini Live API");

        // 2. Send Setup Message (Must be first)
        const setup = {
            setup: {
                model: MODEL,
                generationConfig: {
                    responseModalities: ["AUDIO"],
                    speechConfig: {
                        voiceConfig: { prebuiltVoiceConfig: { voice_name: "Puck" } }
                    }
                },
                systemInstruction: {
                    parts: [{ text: "You are AgentX. Analyze the provided images and audio. Describe any changes you see in the screen frames." }]
                }
            }
        };
        ws.send(JSON.stringify(setup));
    });

    ws.on('message', async function incoming(data) {
        const response = JSON.parse(data.toString());

        // --- VERBOSE LOGGING ---
        console.log("📩 [GOOGLE_RESPONSE]:", JSON.stringify(response, null, 2));

        // 3. Check for Setup Completion
        if (response.setupComplete) {
            console.log("🎊 Setup Complete. Injecting media...");

            try {
                // Fetch assets from Supabase (Update paths to your actual files)
                const imageBase64 = await getSupabaseFile('tests/screen_frame_01.jpg');
                const pcmBase64 = await getSupabaseFile('tests/user_query.pcm');

                // 4. Inject Image Frame
                console.log("📤 Sending Image Frame...");
                ws.send(JSON.stringify({
                    realtimeInput: {
                        mediaChunks: [{
                            mimeType: "image/jpeg",
                            data: imageBase64
                        }]
                    }
                }));

                // 5. Inject Audio Chunk
                console.log("📤 Sending Audio PCM...");
                ws.send(JSON.stringify({
                    realtimeInput: {
                        mediaChunks: [{
                            mimeType: "audio/pcm;rate=16000",
                            data: pcmBase64
                        }]
                    }
                }));

                console.log("⏳ Waiting for model to process and respond...");

            } catch (err) {
                console.error("❌ Error fetching/sending media:", err);
            }
        }

        // 6. Handle Tool Calls or Model Turns
        if (response.serverContent?.modelTurn) {
            console.log("🤖 Model is responding with audio/text parts.");
        }

        // 7. Auto-Exit (Since this is a GitHub Action, we don't want it to hang)
        if (response.serverContent?.turnComplete) {
            console.log("🏁 Turn complete. Closing connection.");
            setTimeout(() => ws.close(), 2000); 
        }
    });

    ws.on('error', (err) => {
        console.error("WebSocket Error:", err);
        process.exit(1);
    });

    ws.on('close', () => {
        console.log("🔌 Connection Closed.");
        process.exit(0);
    });
}

runTest();

