import { GoogleGenerativeAI } from "@google/generative-ai";
import { createClient } from "@supabase/supabase-js";
import WebSocket from "ws"; // Required for Node.js environment

// 1. Setup Environment & Clients
const genAI = new GoogleGenerativeAI(process.env.GEMINI_API_KEY);
const supabase = createClient(
  process.env.SUPABASE_URL,
  process.env.SUPABASE_SERVICE_ROLE_KEY
);

// The exact model ID you specified
const MODEL_ID = "gemini-2.5-flash-native-audio-preview-12-2025";

async function runTest() {
  console.log("--- STARTING GEMINI LIVE VISION TEST ---");

  // 2. Fetch Assets from Supabase
  // Update these bucket names and paths to match your actual Supabase storage
  console.log("Fetching assets from Supabase...");

  const { data: audioBlob, error: aErr } = await supabase.storage.from('assets').download('test-input.pcm');
  const { data: imageBlob, error: iErr } = await supabase.storage.from('assets').download('screen-capture.jpg');

  if (aErr || iErr) {
    console.error("Error fetching assets:", aErr || iErr);
    process.exit(1);
  }

  // Convert Blobs to Base64 strings for the API
  const audioBase64 = Buffer.from(await audioBlob.arrayBuffer()).toString('base64');
  const imageBase64 = Buffer.from(await imageBlob.arrayBuffer()).toString('base64');

  console.log(`Assets loaded: Audio (${audioBase64.length} chars), Image (${imageBase64.length} chars)`);

  // 3. Connect to Gemini Multimodal Live API
  // We use the 'v1alpha' or 'v1beta' endpoint depending on availability
  const model = genAI.getGenerativeModel({ model: MODEL_ID });

  // Note: The Live API in Node requires a WebSocket implementation
  const connection = await model.startChat({
    // Live API Specific Config
    config: {
      generationConfig: {
        responseModalities: ["AUDIO"],
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName: "Puck" } }
        }
      },
      systemInstruction: "You are AgentX, a concise observer. Stay silent unless the screen changes. Analyze the provided image and respond to the audio.",
    }
  });

  // 4. Set up Verbose Logging for everything Google returns
  console.log("--- ESTABLISHING LIVE SESSION ---");

  // In the SDK, we listen to the stream. 
  // For the raw WebSocket approach (required for true "Live" mode in Node):
  const url = `wss://generativelanguage.googleapis.com/ws/google.ai.generativelanguage.v1beta.GenerativeService.BidiGenerateContent?key=${process.env.GEMINI_API_KEY}`;
  const ws = new WebSocket(url);

  ws.on('open', () => {
    console.log("[WS] Connected to Google. Sending Setup...");

    // Step A: Send Setup Configuration (using camelCase for Proto3 JSON)
    const setupMsg = {
      setup: {
        model: MODEL_ID,
        generationConfig: {
          responseModalities: ["AUDIO"],
          speechConfig: { 
            voiceConfig: { prebuiltVoiceConfig: { voiceName: "Puck" } } 
          }
        },
        systemInstruction: {
          parts: [{ text: "You are AgentX, a concise observer. Stay silent unless the screen changes." }]
        }
      }
    };
    ws.send(JSON.stringify(setupMsg));
  });

  ws.on('message', (data) => {
    const response = JSON.parse(data.toString());

    // EXTENSIVE VERBOSE LOGGING
    console.log("\n[GOOGLE RECEIVE]:", JSON.stringify(response, null, 2));

    // Step B: Once setup is confirmed, send the media
    if (response.setupComplete) {
      console.log("[WS] Setup Complete. Streaming Media Chunks...");

      // Send Image (Video Frame)
      ws.send(JSON.stringify({
        realtimeInput: {
          mediaChunks: [{
            mimeType: "image/jpeg",
            data: imageBase64
          }]
        }
      }));

      // Send Audio (PCM)
      ws.send(JSON.stringify({
        realtimeInput: {
          mediaChunks: [{
            mimeType: "audio/pcm;rate=16000",
            data: audioBase64
          }]
        }
      }));

      console.log("[WS] Media sent. Waiting for model response...");
    }

    // Step C: If we get a server content turn, log it specifically
    if (response.serverContent?.modelTurn) {
        console.log("[MODEL TURN DETECTED]");
        const parts = response.serverContent.modelTurn.parts;
        parts.forEach(part => {
            if (part.inlineData) {
                console.log(`[AUDIO RECEIVED]: ${part.inlineData.data.length} bytes of PCM data.`);
            }
            if (part.text) {
                console.log(`[TEXT RECEIVED]: ${part.text}`);
            }
        });

        // For a GitHub Action test, we might want to exit after the first response
        console.log("Test complete. Closing connection.");
        setTimeout(() => process.exit(0), 5000); // Wait 5s to finish receiving audio
    }
  });

  ws.on('error', (err) => {
    console.error("[WS ERROR]:", err);
    process.exit(1);
  });

  ws.on('close', () => {
    console.log("[WS] Connection closed by Google.");
    process.exit(0);
  });
}

runTest().catch(err => {
  console.error("Fatal Error:", err);
  process.exit(1);
});

