    console.log("[WS] Connected to Google. Sending Setup...");

    // Step A: Send Setup Configuration (using camelCase for Proto3 JSON)
    const setupMsg = {
      setup: {
        model: MODEL_ID,
        generationConfig: {
          responseModalities: ["AUDIO"],
          speechConfig: { 
            voiceConfig: { prebuiltVoiceConfig: { voiceName: "Puck" } } 
          }
        },
        systemInstruction: {
          parts: [{ text: "You are AgentX, a concise observer. Stay silent unless the screen changes." }]
        }
      }
    };
    ws.send(JSON.stringify(setupMsg));
  });

  ws.on('message', (data) => {
    const response = JSON.parse(data.toString());

    // EXTENSIVE VERBOSE LOGGING
    console.log("\n[GOOGLE RECEIVE]:", JSON.stringify(response, null, 2));

    // Step B: Once setup is confirmed, send the media
    if (response.setupComplete) {
      console.log("[WS] Setup Complete. Streaming Media Chunks...");

      // Send Image (Video Frame)
      ws.send(JSON.stringify({
        realtimeInput: {
          mediaChunks: [{
            mimeType: "image/jpeg",
            data: imageBase64
          }]
        }
      }));

      // Send Audio (PCM)
      ws.send(JSON.stringify({
        realtimeInput: {
          mediaChunks: [{
            mimeType: "audio/pcm;rate=16000",
            data: audioBase64
          }]
        }
      }));

      console.log("[WS] Media sent. Waiting for model response...");
    }

    // Step C: If we get a server content turn, log it specifically
    if (response.serverContent?.modelTurn) {
        console.log("[MODEL TURN DETECTED]");
        const parts = response.serverContent.modelTurn.parts;
        parts.forEach(part => {
            if (part.inlineData) {
                console.log(`[AUDIO RECEIVED]: ${part.inlineData.data.length} bytes of PCM data.`);
            }
            if (part.text) {
                console.log(`[TEXT RECEIVED]: ${part.text}`);
            }
        });

        // For a GitHub Action test, we might want to exit after the first response
        console.log("Test complete. Closing connection.");
        setTimeout(() => process.exit(0), 5000); // Wait 5s to finish receiving audio
    }
  });

  ws.on('error', (err) => {
    console.error("[WS ERROR]:", err);
    process.exit(1);
  });

  ws.on('close', () => {
    console.log("[WS] Connection closed by Google.");
    process.exit(0);
  });
}

runTest().catch(err => {
  console.error("Fatal Error:", err);
  process.exit(1);
});

